    dailyDurations.set(dayKey, {
      durationMs: existing.durationMs + durationMs,
      nightMs: existing.nightMs + nightMs,
      hasAbsence: existing.hasAbsence || log.absences?.some(a => a.type === 'FULL_DAY'),
      date: date,
    });
  });

  // Calculate daily overtime hours and totals
  for (const [dayKey, { durationMs, date }] of dailyDurations.entries()) {
