      const isNight = h >= 22 || h < 7;
      const nextHour = new Date(current);
      nextHour.setHours(h + 1, 0, 0, 0);
      const chunkEnd = new Date(Math.min(nextHour.getTime(), end.getTime()));

      if (isNight) {
        overlapMs += chunkEnd.getTime() - current.getTime();
      }
      current = chunkEnd;
